  ('social-worker-moex-01054', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '那一份報告建議英國原先分散在各部門的社會工作者，應整合在一個地方政府的社會福利部門 下，社會工作被訓練成綜融社會工作者，提供預防與社區為基礎的服務？', '["貝弗里奇報告書", "韋伯報告書", "希伯罕報告", "葉慈報告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
